1	// Edge function: auth-signup-creator (US-019 + US-020)
2	//
3	// Contract:
4	//   POST { username: string, tiktok_handle?: string, instagram_handle?: string }
5	//     → 200 {
6	//         token: string,
7	//         user_id: string,
8	//         role: 'creator',
9	//         metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status },
10	//       }
11	//       where Status is 'fresh' | 'refreshing' | 'failed'.
12	//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
13	//     → 422 { error: 'HANDLE_REQUIRED' }
14	//     → 409 { error: 'USERNAME_TAKEN' | 'HANDLE_TAKEN' }
15	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
16	//
17	// Auth: none. This is how a creator obtains their first JWT, so the
18	// endpoint is verify_jwt=false at the gateway. The handler itself mints
19	// the token via _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
20	//
21	// Atomicity: the users + creator_profiles + social_links inserts run
22	// inside a single Postgres transaction via the public.auth_signup_creator
23	// RPC (us_019 migration). A failure on any insert rolls back the flow.
24	// Apify dispatch happens AFTER the RPC commits — per spec §5.1, a
25	// dispatch failure does NOT roll back the account (the user gets their
26	// JWT, metrics_status carries the per-platform outcome so the client can
27	// decide whether to retry later or surface a 'refreshing' placeholder).
28	//
29	// Handle normalization: leading '@' is stripped and whitespace trimmed
30	// before the RPC call. Handles are compared case-insensitively (citext),
31	// matching social_links.handle's column type.
32	//
33	// Apify dispatch (US-020): once the RPC commits, we look up the
34	// freshly-inserted social_links rows, then kick one or more Apify runs in
35	// parallel via Promise.allSettled — tiktok_profile for TikTok handles;
36	// ig_details and ig_posts for Instagram handles. Each run is registered
37	// with a per-run webhook pointing back at /functions/v1/apify-webhook so
38	// the receiver can persist the metric_snapshots row when Apify finishes.
39	// The wait window is APIFY_WAIT_SECS (60s); runs that come back
40	// SUCCEEDED within the window are reported as 'fresh' (the webhook will
41	// also arrive and be deduped via the unique index on run_id), otherwise
42	// 'refreshing' and the client polls. A thrown dispatch is 'failed'.
43	//
44	// Pre-refreshing rows: the spec calls for pre-creating metric_snapshots
45	// rows in status='refreshing' before the scrape so the client has
46	// something to read. That's deferred — the existing US-016..US-018 RPCs
47	// INSERT on webhook arrival via ON CONFLICT DO NOTHING, so the row
48	// appears only once Apify finishes. Tracked as a spec gap in progress.txt.
49	//
50	// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling
51	// via a signup_attempts table (does not yet exist). Same status as the
52	// sibling auth-signup-lister — tracked in progress.txt Codebase Patterns.
53	
54	import { createClient, type SupabaseClient } from "npm:@supabase/supabase-js@2";
55	import { signJwt } from "../_shared/jwt.ts";
56	import { corsHeaders } from "../_shared/cors.ts";
57	import {
58	  type ApifyRunResult,
59	  type ApifyWebhookSpec,
60	  runInstagramDetails,
61	  runInstagramPosts,
62	  runTikTokProfile,
63	} from "../_shared/apify.ts";
64	
65	const APIFY_WAIT_SECS = 60;
66	const APIFY_TERMINAL_EVENTS = [
67	  "ACTOR.RUN.SUCCEEDED",
68	  "ACTOR.RUN.FAILED",
69	  "ACTOR.RUN.TIMED_OUT",
70	  "ACTOR.RUN.ABORTED",
71	];
72	
73	type MetricsKey = "tiktok" | "ig_details" | "ig_posts";
74	type MetricsStatus = "fresh" | "refreshing" | "failed";
75	
76	interface SignupRequest {
77	  username?: unknown;
78	  tiktok_handle?: unknown;
79	  instagram_handle?: unknown;
80	}
81	
82	function jsonResponse(status: number, body: unknown): Response {
83	  return new Response(JSON.stringify(body), {
84	    status,
85	    headers: { ...corsHeaders, "Content-Type": "application/json" },
86	  });
87	}
88	
89	function isString(value: unknown): value is string {
90	  return typeof value === "string";
91	}
92	
93	function normalizeHandle(value: unknown): string | null {
94	  if (!isString(value)) return null;
95	  const stripped = value.trim().replace(/^@+/, "").trim();
96	  return stripped.length > 0 ? stripped : null;
97	}
98	
99	Deno.serve(async (req) => {
100	  if (req.method === "OPTIONS") {
101	    return new Response(null, { status: 204, headers: corsHeaders });
102	  }
103	  if (req.method !== "POST") {
104	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
105	  }
106	
107	  let body: SignupRequest;
108	  try {
109	    body = await req.json();
110	  } catch {
111	    return jsonResponse(400, { error: "INVALID_JSON" });
112	  }
113	
114	  const username =
115	    isString(body.username) && body.username.trim().length > 0
116	      ? body.username.trim()
117	      : null;
118	  const tiktokHandle = normalizeHandle(body.tiktok_handle);
119	  const instagramHandle = normalizeHandle(body.instagram_handle);
120	
121	  if (!username) {
122	    return jsonResponse(400, { error: "INVALID_REQUEST" });
123	  }
124	  if (!tiktokHandle && !instagramHandle) {
125	    return jsonResponse(422, { error: "HANDLE_REQUIRED" });
126	  }
127	
128	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
129	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
130	  if (!supabaseUrl || !serviceRoleKey) {
131	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
132	  }
133	
134	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
135	    auth: { persistSession: false, autoRefreshToken: false },
136	  });
137	
138	  const { data, error } = await supabase.rpc("auth_signup_creator", {
139	    p_username: username,
140	    p_tiktok_handle: tiktokHandle,
141	    p_instagram_handle: instagramHandle,
142	  });
143	
144	  if (error) {
145	    console.error("auth_signup_creator rpc error", error);
146	    return jsonResponse(500, { error: "DB_ERROR" });
147	  }
148	
149	  const result = data as { user_id?: string; error?: string } | null;
150	  if (result?.error === "USERNAME_TAKEN") {
151	    return jsonResponse(409, { error: "USERNAME_TAKEN" });
152	  }
153	  if (result?.error === "HANDLE_TAKEN") {
154	    return jsonResponse(409, { error: "HANDLE_TAKEN" });
155	  }
156	  if (!result?.user_id) {
157	    console.error("auth_signup_creator returned unexpected shape", result);
158	    return jsonResponse(500, { error: "DB_ERROR" });
159	  }
160	
161	  const userId = result.user_id;
162	  const sessionId = crypto.randomUUID();
163	  let token: string;
164	  try {
165	    token = await signJwt({
166	      sub: userId,
167	      app_role: "creator",
168	      session_id: sessionId,
169	    });
170	  } catch (err) {
171	    console.error("signJwt failed", err);
172	    return jsonResponse(500, { error: "JWT_ERROR" });
173	  }
174	
175	  const metricsStatus = await dispatchApifyRuns({
176	    supabase,
177	    supabaseUrl,
178	    userId,
179	    tiktokHandle,
180	    instagramHandle,
181	  });
182	
183	  return jsonResponse(200, {
184	    token,
185	    user_id: userId,
186	    role: "creator",
187	    metrics_status: metricsStatus,
188	  });
189	});
190	
191	// Dispatches the Apify runs required for the freshly-created creator
192	// account. Returns a partial metrics_status map keyed by platform. If
193	// APIFY_KEY or APIFY_WEBHOOK_SECRET is unset (e.g. local dev without
194	// Apify credentials), logs a warning and returns {} — the account is
195	// still usable, the client just won't see any metrics until a future
196	// scrape picks it up. A failure to dispatch a single platform does not
197	// affect the others.
198	// deno-lint-ignore no-explicit-any -- supabase-js generic args differ between
199	// the createClient call above (inferred as public schema) and any helper
200	// import; typing this parameter loosely avoids a widening mismatch.
201	async function dispatchApifyRuns(params: {
202	  supabase: SupabaseClient<any, any, any>;
203	  supabaseUrl: string;
204	  userId: string;
205	  tiktokHandle: string | null;
206	  instagramHandle: string | null;
207	}): Promise<Partial<Record<MetricsKey, MetricsStatus>>> {
208	  const { supabase, supabaseUrl, userId, tiktokHandle, instagramHandle } =
209	    params;
210	  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};
211	
212	  const apifyKey = Deno.env.get("APIFY_KEY");
213	  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
214	  if (!apifyKey || !webhookSecret) {
215	    console.warn(
216	      "apify dispatch skipped: APIFY_KEY or APIFY_WEBHOOK_SECRET missing",
217	    );
218	    return metricsStatus;
219	  }
220	
221	  const { data: links, error: linksError } = await supabase
222	    .from("social_links")
223	    .select("id,platform")
224	    .eq("user_id", userId);
225	  if (linksError) {
226	    console.error("social_links lookup failed", linksError);
227	    return metricsStatus;
228	  }
229	
230	  const linkRows = (links ?? []) as Array<{ id: string; platform: string }>;
231	  const tiktokLinkId = linkRows.find((l) => l.platform === "tiktok")?.id;
232	  const igLinkId = linkRows.find((l) => l.platform === "instagram")?.id;
233	
234	  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
235	  const buildWebhook = (
236	    linkId: string,
237	    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
238	  ): ApifyWebhookSpec => ({
239	    eventTypes: APIFY_TERMINAL_EVENTS,
240	    requestUrl: webhookUrl,
241	    // Build a `resource` object field-by-field using dot-notation
242	    // placeholders. Apify only substitutes placeholders that appear inside
243	    // quoted JSON string values when `shouldInterpolateStrings: true`; bare
244	    // unquoted `{{var}}` substitutes the raw JSON value but can't round-trip
245	    // through JSON.stringify. Sticking to the quoted form keeps the template
246	    // valid JSON before substitution and readable by any linter.
247	    // apify-webhook/index.ts validResource requires id, defaultDatasetId,
248	    // status, and actId on the resource object.
249	    payloadTemplate: JSON.stringify({
250	      eventType: "{{eventType}}",
251	      resource: {
252	        id: "{{resource.id}}",
253	        defaultDatasetId: "{{resource.defaultDatasetId}}",
254	        status: "{{resource.status}}",
255	        actId: "{{resource.actId}}",
256	      },
257	      social_link_id: linkId,
258	      scrape_mode: scrapeMode,
259	      run_id: "{{resource.id}}",
260	      dataset_id: "{{resource.defaultDatasetId}}",
261	    }),
262	    headersTemplate: JSON.stringify({
263	      "X-Apify-Webhook-Secret": webhookSecret,
264	    }),
265	    shouldInterpolateStrings: true,
266	  });
267	
268	  interface Task {
269	    key: MetricsKey;
270	    run: () => Promise<ApifyRunResult>;
271	  }
272	  const tasks: Task[] = [];
273	  if (tiktokHandle && tiktokLinkId) {
274	    tasks.push({
275	      key: "tiktok",
276	      run: () =>
277	        runTikTokProfile(tiktokHandle, {
278	          waitSecs: APIFY_WAIT_SECS,
279	          webhooks: [buildWebhook(tiktokLinkId, "tiktok_profile")],
280	        }),
281	    });
282	  }
283	  if (instagramHandle && igLinkId) {
284	    tasks.push({
285	      key: "ig_details",
286	      run: () =>
287	        runInstagramDetails(instagramHandle, {
288	          waitSecs: APIFY_WAIT_SECS,
289	          webhooks: [buildWebhook(igLinkId, "ig_details")],
290	        }),
291	    });
292	    tasks.push({
293	      key: "ig_posts",
294	      run: () =>
295	        runInstagramPosts(instagramHandle, {
296	          waitSecs: APIFY_WAIT_SECS,
297	          webhooks: [buildWebhook(igLinkId, "ig_posts")],
298	        }),
299	    });
300	  }
301	
302	  if (tasks.length === 0) return metricsStatus;
303	
304	  const settled = await Promise.allSettled(tasks.map((t) => t.run()));
305	  settled.forEach((outcome, i) => {
306	    const key = tasks[i].key;
307	    if (outcome.status === "fulfilled") {
308	      // Apify's waitForFinish returns either SUCCEEDED (complete) or a
309	      // transitional status when the wait expires: READY, RUNNING,
310	      // TIMING-OUT, ABORTING. All four mean the webhook will still
311	      // fire and complete the snapshot, so they map to 'refreshing'.
312	      // Anything else (e.g. FAILED, ABORTED, TIMED-OUT terminal) is a
313	      // terminal non-success — 'failed'. The webhook receiver will
314	      // also write the failed row; the two converge via the run_id
315	      // unique index.
316	      const s = outcome.value.status;
317	      metricsStatus[key] = s === "SUCCEEDED"
318	        ? "fresh"
319	        : s === "READY" || s === "RUNNING" ||
320	            s === "TIMING-OUT" || s === "ABORTING"
321	        ? "refreshing"
322	        : "failed";
323	    } else {
324	      console.error(`apify ${key} dispatch failed`, outcome.reason);
325	      metricsStatus[key] = "failed";
326	    }
327	  });
328	
329	  return metricsStatus;
330	}
